import React, { useState } from 'react';
import { useVisualizerStore } from '../../store/useVisualizerStore';
import { Send, Zap, BrainCircuit, Activity, User } from 'lucide-react';
import { Link } from 'react-router-dom';

export const Sidebar: React.FC = () => {
    const [prompt, setPrompt] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const [errorMsg, setErrorMsg] = useState('');

    const { animation, currentStepIndex, setAnimation } = useVisualizerStore();
    const currentStep = animation?.steps[currentStepIndex];

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!prompt.trim()) return;

        setIsLoading(true);
        setErrorMsg('');

        try {
            const response = await fetch('http://localhost:5000/api/ai/generate', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ prompt })
            });

            if (!response.ok) {
                const errorData = await response.json().catch(() => null);
                throw new Error(errorData?.details || errorData?.error || 'Failed to generate visualization');
            }

            const animationData = await response.json();
            setAnimation(animationData);
            setPrompt('');
        } catch (error: any) {
            console.error(error);
            setErrorMsg(error.message || 'Error connecting to AI backend.');
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="w-96 flex flex-col h-full bg-zinc-950/80 border-r border-white/10 backdrop-blur-xl relative z-10 transition-all duration-300">

            {/* Brand Header */}
            <div className="p-6 border-b border-white/5 flex items-center justify-between">
                <div className="flex items-center gap-3">
                    <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-violet-600 to-indigo-600 flex items-center justify-center shadow-[0_0_20px_rgba(124,58,237,0.3)]">
                        <BrainCircuit className="text-white w-6 h-6" />
                    </div>
                    <div>
                        <h1 className="text-2xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-violet-400 to-indigo-400">AlgoVerse</h1>
                        <p className="text-xs text-zinc-400 font-medium">AI-Powered DSA Visualizer</p>
                    </div>
                </div>
                <Link to="/profile" className="w-10 h-10 rounded-xl bg-zinc-900 border border-zinc-800 flex items-center justify-center hover:bg-zinc-800 hover:border-zinc-700 transition-colors cursor-pointer group">
                    <User className="text-zinc-400 group-hover:text-white w-5 h-5 transition-colors" />
                </Link>
            </div>

            {/* Main Info Area */}
            <div className="flex-1 overflow-y-auto p-6 space-y-6 custom-scrollbar">
                {errorMsg && (
                    <div className="p-4 bg-rose-500/10 border border-rose-500/20 rounded-xl">
                        <h3 className="text-sm font-semibold text-rose-400 mb-1">Generation Failed</h3>
                        <p className="text-xs text-rose-300/80 leading-relaxed">{errorMsg}</p>
                    </div>
                )}

                {!animation ? (
                    <div className="text-center py-10 space-y-4">
                        <Zap className="w-12 h-12 text-zinc-600 mx-auto" />
                        <h3 className="text-lg font-medium text-zinc-300">Awaiting Commands</h3>
                        <p className="text-sm text-zinc-500 max-w-[250px] mx-auto">
                            Ask AlgoVerse to visualize any data structure or algorithm operation.
                        </p>
                    </div>
                ) : (
                    <div className="space-y-6">
                        <div className="mb-4">
                            <h2 className="text-xl font-semibold text-white mb-2">{animation.title}</h2>
                            <div className="flex gap-2">
                                <span className="px-3 py-1 rounded-full text-xs font-semibold bg-violet-500/20 text-violet-300 border border-violet-500/30">
                                    Time: {animation.complexity.time}
                                </span>
                                <span className="px-3 py-1 rounded-full text-xs font-semibold bg-emerald-500/20 text-emerald-300 border border-emerald-500/30">
                                    Space: {animation.complexity.space}
                                </span>
                            </div>
                        </div>

                        <div className="glass-panel rounded-2xl p-5 relative overflow-hidden">
                            <div className="absolute top-0 left-0 w-1 h-full bg-gradient-to-b from-indigo-500 to-violet-500"></div>
                            <h3 className="text-sm text-zinc-400 font-semibold mb-2 flex items-center gap-2">
                                <Activity className="w-4 h-4" />
                                Step {currentStepIndex + 1} of {animation.steps.length}
                            </h3>
                            <p className="text-base text-zinc-200 leading-relaxed font-medium">
                                {currentStep?.explanation || 'Loading explanation...'}
                            </p>
                        </div>
                    </div>
                )}
            </div>

            {/* Input Area */}
            <div className="p-6 border-t border-white/5 bg-zinc-950/50">
                <form onSubmit={handleSubmit} className="relative">
                    <input
                        type="text"
                        value={prompt}
                        onChange={(e) => setPrompt(e.target.value)}
                        disabled={isLoading}
                        placeholder='e.g., "Insert 42 into a BST"'
                        className="w-full bg-zinc-900/80 border border-white/10 rounded-xl py-3 pl-4 pr-12 text-sm text-white focus:outline-none focus:ring-2 focus:ring-violet-500/50 transition-all font-inter placeholder-zinc-600"
                    />
                    <button
                        type="submit"
                        disabled={isLoading || !prompt.trim()}
                        className="absolute right-2 top-1/2 -translate-y-1/2 p-1.5 rounded-lg bg-violet-600 hover:bg-violet-500 text-white transition-colors disabled:opacity-50 disabled:hover:bg-violet-600"
                    >
                        {isLoading ? (
                            <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                        ) : (
                            <Send className="w-4 h-4" />
                        )}
                    </button>
                </form>
                <p className="text-xs text-zinc-500 mt-3 text-center">
                    Powered by Gemini 2.5 Flash
                </p>
            </div>

        </div>
    );
};

import React, { useEffect, useState, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { useVisualizerStore } from '../../store/useVisualizerStore';
import * as d3 from 'd3';

interface GraphNode {
    id: string;
    value: string;
    x?: number;
    y?: number;
}

interface GraphEdge {
    source: string;
    target: string;
    weight?: number;
}

interface GraphState {
    nodes: GraphNode[];
    edges: GraphEdge[];
}

export const GraphVisualizer: React.FC = () => {
    const { animation, currentStepIndex } = useVisualizerStore();
    const containerRef = useRef<HTMLDivElement>(null);

    const currentStep = animation?.steps[currentStepIndex];
    if (!currentStep) return null;

    const state = currentStep.state as GraphState;
    const rawNodes = state.nodes || [];
    const rawEdges = state.edges || [];
    const highlights = currentStep.highlights || [];

    const [simNodes, setSimNodes] = useState<any[]>([]);
    const [simEdges, setSimEdges] = useState<any[]>([]);

    // D3 Force Simulation setup
    useEffect(() => {
        if (!containerRef.current) return;

        const width = 600;
        const height = 400;

        // We make a copy of nodes and edges because d3 mutates them
        const nodesCopy = rawNodes.map(n => ({ ...n }));
        const edgesCopy = rawEdges.map(e => ({ ...e, source: e.source, target: e.target }));

        const simulation = d3.forceSimulation(nodesCopy)
            .force("link", d3.forceLink(edgesCopy).id((d: any) => d.id).distance(120))
            .force("charge", d3.forceManyBody().strength(-400))
            .force("center", d3.forceCenter(width / 2, height / 2))
            .on("tick", () => {
                setSimNodes([...nodesCopy]);
                setSimEdges([...edgesCopy]);
            });

        // Run for a few ticks to stabilize initially
        simulation.tick(50);

        return () => {
            simulation.stop();
        };
    }, [rawNodes, rawEdges]);

    return (
        <div ref={containerRef} className="relative w-[600px] h-[400px]">

            {/* SVG Edges Layer */}
            <svg className="absolute inset-0 w-full h-full pointer-events-none text-zinc-600">
                <AnimatePresence>
                    {simEdges.map((edge) => {
                        const sourceHighlight = highlights.includes(edge.source.id);
                        const targetHighlight = highlights.includes(edge.target.id);
                        const isHighlightedEdge = sourceHighlight && targetHighlight;

                        return (
                            <g key={`${edge.source.id}-${edge.target.id}`}>
                                <motion.line
                                    initial={{ opacity: 0 }}
                                    animate={{
                                        opacity: 1,
                                        stroke: isHighlightedEdge ? '#c084fc' : '#52525b',
                                        strokeWidth: isHighlightedEdge ? 4 : 2,
                                    }}
                                    x1={edge.source.x}
                                    y1={edge.source.y}
                                    x2={edge.target.x}
                                    y2={edge.target.y}
                                    className="transition-colors duration-300"
                                />

                                {/* Edge Weight Optional Label */}
                                {edge.weight && (
                                    <text
                                        x={(edge.source.x + edge.target.x) / 2}
                                        y={(edge.source.y + edge.target.y) / 2 - 10}
                                        fill="#a1a1aa"
                                        fontSize="12"
                                        textAnchor="middle"
                                    >
                                        {edge.weight}
                                    </text>
                                )}
                            </g>
                        );
                    })}
                </AnimatePresence>
            </svg>

            {/* HTML Nodes Layer */}
            <div className="absolute inset-0 w-full h-full pointer-events-none">
                <AnimatePresence>
                    {simNodes.map((node) => {
                        const isHighlighted = highlights.includes(node.id) || highlights.includes(node.value);

                        return (
                            <motion.div
                                key={node.id}
                                initial={{ opacity: 0, scale: 0 }}
                                animate={{
                                    opacity: 1,
                                    scale: 1,
                                    x: node.x - 24, // center it (w-12 = 48 -> offset 24)
                                    y: node.y - 24,
                                }}
                                exit={{ opacity: 0, scale: 0 }}
                                transition={{ type: "spring", stiffness: 300, damping: 25 }}
                                className={`
                  absolute w-12 h-12 rounded-full border-2 flex items-center justify-center font-bold text-lg
                  shadow-xl transition-colors pointer-events-auto
                  ${isHighlighted
                                        ? 'border-violet-400 bg-violet-900/80 text-white shadow-[0_0_20px_rgba(139,92,246,0.6)] z-10'
                                        : 'border-zinc-700 bg-zinc-800 text-zinc-300 z-0'
                                    }
                `}
                            >
                                {node.value}
                            </motion.div>
                        );
                    })}
                </AnimatePresence>
            </div>

        </div>
    );
};

import React, { useMemo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { useVisualizerStore } from '../../store/useVisualizerStore';
import * as d3 from 'd3';

interface TreeNode {
    id: string;
    value: number | string;
    left?: TreeNode | null;
    right?: TreeNode | null;
}

interface TreeState {
    tree: TreeNode | null;
}

export const TreeVisualizer: React.FC = () => {
    const { animation, currentStepIndex } = useVisualizerStore();

    const currentStep = animation?.steps[currentStepIndex];
    if (!currentStep) return null;

    const state = currentStep.state as TreeState;
    const root = state.tree;
    const highlights = currentStep.highlights || [];

    // Use D3 to calculate tree layout
    const { nodes, links } = useMemo(() => {
        if (!root) return { nodes: [], links: [] };

        // Convert to D3 hierarchy
        const hierarchy = d3.hierarchy<TreeNode>(root, d => {
            const children = [];
            // D3 expects array of children. If left/right exist we push them,
            // If one is missing but the other exists, we need to push a dummy node
            // to maintain correct Left/Right visual structure in binary trees.
            if (d.left || d.right) {
                children.push(d.left || { id: `dummy-l-${d.id}`, value: '', isDummy: true });
                children.push(d.right || { id: `dummy-r-${d.id}`, value: '', isDummy: true });
            }
            return children as TreeNode[];
        });

        // Create a tree layout
        // Width and height here are logical units.
        const treeLayout = d3.tree<TreeNode>().nodeSize([80, 100]);
        const rootNode = treeLayout(hierarchy);

        const nodesList = rootNode.descendants();
        const linksList = rootNode.links();

        // Center the root
        nodesList.forEach(n => {
            // Shift down slightly
            n.y += 50;
        });

        return { nodes: nodesList, links: linksList };
    }, [root]);

    return (
        <div className="relative w-full h-[500px] flex justify-center overflow-visible">

            {/* Edges - SVG Layer */}
            <svg className="absolute inset-0 w-full h-full pointer-events-none" style={{ overflow: 'visible', transform: 'translateX(50%)' }}>
                <g>
                    <AnimatePresence>
                        {links.map((link) => {
                            if ((link.target.data as any).isDummy || (link.source.data as any).isDummy) return null;

                            const sourceHighlight = highlights.includes(link.source.data.id) || highlights.includes(String(link.source.data.value));
                            const targetHighlight = highlights.includes(link.target.data.id) || highlights.includes(String(link.target.data.value));
                            const isHighlightedEdge = sourceHighlight && targetHighlight;

                            return (
                                <motion.path
                                    key={`${link.source.data.id}-${link.target.data.id}`}
                                    initial={{ opacity: 0, pathLength: 0 }}
                                    animate={{
                                        opacity: 1,
                                        pathLength: 1,
                                        stroke: isHighlightedEdge ? '#c084fc' : '#52525b', // purple-400 or zinc-600
                                        strokeWidth: isHighlightedEdge ? 4 : 2,
                                    }}
                                    exit={{ opacity: 0 }}
                                    transition={{ duration: 0.5, ease: "easeInOut" }}
                                    fill="none"
                                    d={`M ${link.source.x} ${link.source.y} L ${link.target.x} ${link.target.y}`}
                                    className="transition-colors duration-300 drop-shadow-md"
                                />
                            );
                        })}
                    </AnimatePresence>
                </g>
            </svg>

            {/* Nodes - HTML Layer */}
            <div className="absolute inset-0 w-full h-full pointer-events-none" style={{ transform: 'translateX(50%)' }}>
                <AnimatePresence>
                    {nodes.map((node) => {
                        if ((node.data as any).isDummy) return null;

                        const isHighlighted = highlights.includes(node.data.id) || highlights.includes(String(node.data.value));

                        return (
                            <motion.div
                                key={node.data.id}
                                layoutId={`node-${node.data.id}`}
                                initial={{ opacity: 0, scale: 0 }}
                                animate={{
                                    opacity: 1,
                                    scale: 1,
                                    x: node.x - 24, // center offset (width/2)
                                    y: node.y - 24,
                                }}
                                exit={{ opacity: 0, scale: 0 }}
                                transition={{ type: "spring", stiffness: 300, damping: 25 }}
                                className={`
                  absolute w-12 h-12 rounded-full border-2 flex items-center justify-center font-bold text-lg
                  shadow-xl transition-colors pointer-events-auto
                  ${isHighlighted
                                        ? 'border-violet-400 bg-violet-900/80 text-white shadow-[0_0_20px_rgba(139,92,246,0.6)] z-10'
                                        : 'border-zinc-700 bg-zinc-800 text-zinc-300 z-0'
                                    }
                `}
                            >
                                {node.data.value}
                            </motion.div>
                        );
                    })}
                </AnimatePresence>
            </div>

        </div>
    );
};

export type DataStructureType =
    | 'array'
    | 'linked_list'
    | 'stack'
    | 'queue'
    | 'binary_tree'
    | 'graph'
    | 'sorting'
    | 'dp'
    | 'backtracking'
    | 'bit_manipulation';

export interface BaseState {
    [key: string]: any;
}

export interface TransitionStep<T = BaseState> {
    action: string;
    explanation: string;
    state: T;
    highlights?: string[]; // IDs of nodes/elements to highlight
    pointers?: Record<string, string | number>; // e.g. { i: 0, j: 2, pivot: 5 }
}

export interface Complexity {
    time: string;
    space: string;
}

export interface AlgorithmAnimation<T = BaseState> {
    structure: DataStructureType;
    title: string;
    complexity: Complexity;
    steps: TransitionStep<T>[];
}
